#!/usr/bin/env python3
import os
import re
from pathlib import Path
from collections import defaultdict

# Starting package
START_PKG = "internal/server/evaluation"
REPO_ROOT = "/workspace"
MODULE_PREFIX = "go.flipt.io/flipt"

# Track visited packages to avoid infinite loops
visited = set()
# Track all dependencies: pkg -> set of direct dependencies
all_deps = defaultdict(set)
# Track the order we discover packages
discovered_order = []

def get_internal_imports(pkg_path):
    """Extract internal imports from all .go files in a package"""
    imports = set()
    pkg_full_path = os.path.join(REPO_ROOT, pkg_path)

    if not os.path.isdir(pkg_full_path):
        return imports

    for file in os.listdir(pkg_full_path):
        if file.endswith(".go") and not file.endswith("_test.go"):
            file_path = os.path.join(pkg_full_path, file)
            with open(file_path, 'r') as f:
                content = f.read()
                # Find all import blocks
                import_pattern = r'import\s*\((.*?)\)|import\s+"([^"]+)"'
                for match in re.finditer(import_pattern, content, re.DOTALL):
                    if match.group(1):  # multi-line import
                        lines = match.group(1).split('\n')
                        for line in lines:
                            # Extract import path
                            line = line.strip()
                            if line.startswith('"') and MODULE_PREFIX in line:
                                import_path = line.strip('"')
                                imports.add(import_path)
                    elif match.group(2):  # single-line import
                        import_path = match.group(2)
                        if MODULE_PREFIX in import_path:
                            imports.add(import_path)

    # Convert full paths to relative paths
    relative_imports = set()
    for imp in imports:
        if imp.startswith(MODULE_PREFIX + "/"):
            rel = imp[len(MODULE_PREFIX) + 1:]
            relative_imports.add(rel)

    return relative_imports

def normalize_path(path):
    """Remove version suffix if present"""
    # Remove /v2 suffix if present
    if path.endswith("/v2"):
        return path[:-3]
    return path

def traverse(pkg):
    """Recursively traverse dependencies"""
    if pkg in visited:
        return

    visited.add(pkg)
    discovered_order.append(pkg)

    # Get direct imports
    direct_deps = get_internal_imports(pkg)

    for dep in direct_deps:
        dep = normalize_path(dep)
        if dep not in all_deps[pkg]:
            all_deps[pkg].add(dep)
            # Recursively traverse
            if dep not in visited:
                traverse(dep)

# Start traversal
traverse(START_PKG)

print("Discovered packages:")
for pkg in discovered_order:
    print(f"  {pkg}")

print("\nAll dependencies:")
for pkg in discovered_order:
    if all_deps[pkg]:
        print(f"{pkg} -> {all_deps[pkg]}")

print("\nTopological sort needed...")

# Topological sort
sorted_pkgs = []
in_degree = defaultdict(int)

# Build the graph
all_packages = set(discovered_order)
for pkg in all_packages:
    for dep in all_deps[pkg]:
        if dep in all_packages:
            in_degree[dep] += 1  # Wait, this is backwards

# Actually let's rebuild: if pkg A depends on pkg B, then B should come before A
edges = defaultdict(set)
for pkg in all_packages:
    for dep in all_deps[pkg]:
        if dep in all_packages:
            edges[dep].add(pkg)  # B -> A means B should come before A

# Calculate in-degree correctly
for pkg in all_packages:
    if pkg not in in_degree:
        in_degree[pkg] = 0

for pkg in all_packages:
    for dep in all_deps[pkg]:
        if dep in all_packages:
            in_degree[pkg] += 1

# Kahn's algorithm
queue = [pkg for pkg in all_packages if in_degree[pkg] == 0]
sorted_pkgs = []

while queue:
    node = queue.pop(0)
    sorted_pkgs.append(node)

    for neighbor in edges[node]:
        in_degree[neighbor] -= 1
        if in_degree[neighbor] == 0:
            queue.append(neighbor)

print("\nTopologically sorted:")
for pkg in sorted_pkgs:
    print(f"  {pkg}")

EOF
