        # Find all import blocks and single imports
        # Pattern 1: import ( ... )
        import_block_pattern = r'import\s*\((.*?)\)'
        for match in re.finditer(import_block_pattern, content, re.DOTALL):
            block = match.group(1)
            for line in block.split('\n'):
                line = line.strip()
                if line.startswith('"'):
                    path = line.strip('"').strip()
                    if path:
                        imports.add(path)
                elif line and not line.startswith('/'):
                    # Handle aliased imports
                    parts = line.split()
                    for part in parts:
                        if part.startswith('"'):
                            path = part.strip('"')
                            if path:
                                imports.add(path)

        # Pattern 2: import "..."
        single_import_pattern = r'import\s+"([^"]+)"'
        for match in re.finditer(single_import_pattern, content):
            imports.add(match.group(1))
    except:
        pass

    return imports

def get_internal_imports(pkg_path):
    """Get all internal imports from a package"""
    internal_imports = set()
    pkg_full_path = os.path.join(REPO_ROOT, pkg_path)

    if not os.path.isdir(pkg_full_path):
        return internal_imports

    # Find all .go files in the package (excluding _test.go)
    for file in os.listdir(pkg_full_path):
        if file.endswith(".go") and not file.endswith("_test.go"):
            file_path = os.path.join(pkg_full_path, file)
            imports = extract_imports_from_file(file_path)
            for imp in imports:
                if MODULE_PREFIX in imp:
                    # Convert to relative path
                    if imp.startswith(MODULE_PREFIX + "/"):
                        rel = imp[len(MODULE_PREFIX) + 1:]
                        rel = normalize_path(rel)
                        internal_imports.add(rel)
                    elif imp == MODULE_PREFIX:
                        # Root package, though unlikely
                        pass

    return internal_imports

