    if graph[pkg]:
        deps = ", ".join(sorted(graph[pkg]))
        print(f"{pkg}")
        print(f"  → depends on: {deps}")
    else:
        print(f"{pkg}")
        print(f"  → depends on: (nothing - leaf package)")

print("\n\nAll packages discovered:")
print("-" * 80)
for pkg in sorted(visited):
    print(f"  {pkg}")

# Now do topological sort
print("\n\nTopological Sort (Kahn's algorithm):")
print("-" * 80)

